import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for optimized matrix multiplication using cuBLAS-like approach
matmul_optimized_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

torch::Tensor matmul_optimized_cuda(torch::Tensor A, torch::Tensor B) {
    cublasHandle_t handle;
    cublasCreate(&handle);

    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    auto C = torch::zeros({M, N}, A.options());

    float alpha = 1.0f;
    float beta = 0.0f;

    // Use cuBLAS SGEMM for optimal performance
    cublasSgemm(handle,
                CUBLAS_OP_N, CUBLAS_OP_N,
                N, M, K,
                &alpha,
                B.data_ptr<float>(), N,
                A.data_ptr<float>(), K,
                &beta,
                C.data_ptr<float>(), N);

    cublasDestroy(handle);
    return C;
}
"""

matmul_optimized_cpp_source = (
    "torch::Tensor matmul_optimized_cuda(torch::Tensor A, torch::Tensor B);"
)

# Compile the inline CUDA code for optimized matrix multiplication
matmul_optimized = load_inline(
    name="matmul_optimized",
    cpp_sources=matmul_optimized_cpp_source,
    cuda_sources=matmul_optimized_source,
    functions=["matmul_optimized_cuda"],
    verbose=True,
    extra_cflags=["-lcublas"],
    extra_ldflags=["-lcublas"],
)

class ModelNew(nn.Module):
    """
    Optimized model that performs matrix multiplication using cuBLAS for maximum performance
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.matmul_optimized = matmul_optimized

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Performs optimized matrix multiplication of A and B using cuBLAS.

        Args:
            A: Input tensor of shape (M, K)
            B: Input tensor of shape (K, N)

        Returns:
            Output tensor of shape (M, N)
        """
        return self.matmul_optimized.matmul_optimized_cuda(A, B)

M = 256
N = 256
K = 131072

def get_inputs():
    A = torch.randn(M, K).cuda()
    B = torch.randn(K, N).cuda()
    return [A, B]

def get_init_inputs():
    return []  # No special initialization inputs needed

